import React, { useState } from "react";
import jsPDF from "jspdf";

export default function ResumeChatbot() {
  const [step, setStep] = useState(0);
  const [formData, setFormData] = useState({
    name: "",
    role: "",
    education: "",
    skills: "",
    projects: ""
  });

  const questions = [
    "Enter your full name:",
    "Enter your desired job role:",
    "Enter your education:",
    "Enter your skills (comma separated):",
    "Enter your projects:"
  ];

  const keys = Object.keys(formData);

  const handleInput = (e) => {
    setFormData({ ...formData, [keys[step]]: e.target.value });
  };

  const nextStep = () => {
    if (step < questions.length - 1) {
      setStep(step + 1);
    }
  };

  const generateResume = () => {
    return {
      name: formData.name,
      role: formData.role,
      education: formData.education,
      skills: formData.skills.split(","),
      projects: formData.projects.split(",")
    };
  };

  // ⭐ PROFESSIONAL PDF FORMAT
  const downloadPDF = () => {
    const data = generateResume();
    const doc = new jsPDF();

    let y = 20;

    // Name
    doc.setFontSize(18);
    doc.text(data.name, 10, y);
    y += 10;

    // Role
    doc.setFontSize(12);
    doc.text(data.role, 10, y);
    y += 10;

    // Line
    doc.line(10, y, 200, y);
    y += 10;

    // Education
    doc.setFontSize(14);
    doc.text("Education", 10, y);
    y += 8;

    doc.setFontSize(11);
    doc.text(data.education, 10, y);
    y += 10;

    // Skills
    doc.setFontSize(14);
    doc.text("Skills", 10, y);
    y += 8;

    data.skills.forEach(skill => {
      doc.text("• " + skill.trim(), 10, y);
      y += 6;
    });

    y += 5;

    // Projects
    doc.setFontSize(14);
    doc.text("Projects", 10, y);
    y += 8;

    data.projects.forEach(project => {
      doc.text("• " + project.trim(), 10, y);
      y += 6;
    });

    y += 10;

    // Summary
    doc.setFontSize(14);
    doc.text("Summary", 10, y);
    y += 8;

    doc.setFontSize(11);
    doc.text(
      `Motivated ${data.role} with skills in ${data.skills.join(", ")}.`,
      10,
      y
    );

    doc.save("Professional_Resume.pdf");
  };

  const resumePreview = generateResume();

  return (
    <div style={{
      minHeight: "100vh",
      display: "flex",
      justifyContent: "center",
      alignItems: "center",
      background: "linear-gradient(135deg, #1e3c72, #2a5298)"
    }}>

      <div style={{
        width: "650px",
        backdropFilter: "blur(15px)",
        background: "rgba(255,255,255,0.1)",
        borderRadius: "20px",
        padding: "25px",
        boxShadow: "0 8px 32px rgba(0,0,0,0.3)",
        color: "white"
      }}>

        <h2 style={{ textAlign: "center" }}>💼 Smart Resume Builder</h2>

        {step < questions.length ? (
          <>
            <p>{questions[step]}</p>
            <input
              onChange={handleInput}
              style={{
                width: "100%",
                padding: "10px",
                borderRadius: "10px",
                border: "none",
                marginTop: "5px"
              }}
            />
            <button onClick={nextStep} style={{ marginTop: "10px" }}>
              Next
            </button>
          </>
        ) : (
          <>
            {/* ⭐ RESUME PREVIEW */}
            <div style={{
              background: "white",
              color: "black",
              padding: "15px",
              borderRadius: "10px",
              marginBottom: "10px"
            }}>
              <h2>{resumePreview.name}</h2>
              <p>{resumePreview.role}</p>
              <hr />

              <h3>Education</h3>
              <p>{resumePreview.education}</p>

              <h3>Skills</h3>
              <ul>
                {resumePreview.skills.map((s, i) => (
                  <li key={i}>{s}</li>
                ))}
              </ul>

              <h3>Projects</h3>
              <ul>
                {resumePreview.projects.map((p, i) => (
                  <li key={i}>{p}</li>
                ))}
              </ul>

              <h3>Summary</h3>
              <p>
                Motivated {resumePreview.role} with skills in {resumePreview.skills.join(", ")}.
              </p>
            </div>

            <button onClick={downloadPDF}>
              ⬇ Download Professional PDF
            </button>
          </>
        )}

      </div>
    </div>
  );
}
